#!/usr/bin/perl -I/home/cdyreson/public_html/cgi-bin/perl/pm
 
# ****************************************************************
# starter is a Perl program and CGI-bin script that does the quiz
# entry stuff to a quiz generated by QuizMaker.  For more info surf to
#       http://www.cs.jcu.edu.au/~curtis/software.html
